    ('Sea scallop', 'Placopecten magellanicus', 'animal', ARRAY['scallop', 'scallops', 'bay scallop', 'sea scallops']::text[]),
    ('Longfin squid', 'Doryteuthis pealeii', 'animal', ARRAY['squid', 'calamari', 'squid rings']::text[]),
    ('Common octopus', 'Octopus vulgaris', 'animal', ARRAY['octopus', 'pulpo', 'octopus tentacle']::text[]),
    ('Honey bee', 'Apis mellifera', 'animal', ARRAY['honey', 'raw honey', 'bee honey', 'wildflower honey']::text[]),

    -- ── Fungi ────────────────────────────────────────────────────────────────
    ('Shiitake', 'Lentinula edodes', 'fungus', ARRAY['shiitake mushroom', 'shiitake mushrooms', 'shitake']::text[]),
    ('Button mushroom', 'Agaricus bisporus', 'fungus', ARRAY['white mushroom', 'cremini', 'cremini mushroom', 'baby bella', 'portobello', 'portobello mushroom', 'portabella', 'champignon']::text[]),
    ('Oyster mushroom', 'Pleurotus ostreatus', 'fungus', ARRAY['oyster mushrooms', 'pearl oyster mushroom']::text[]),
    ('Lion''s mane', 'Hericium erinaceus', 'fungus', ARRAY['lions mane', 'lion mane mushroom', 'pom pom mushroom']::text[]),
    ('Chanterelle', 'Cantharellus cibarius', 'fungus', ARRAY['chanterelles', 'golden chanterelle', 'girolle']::text[]),
    ('Porcini', 'Boletus edulis', 'fungus', ARRAY['cep', 'ceps', 'king bolete', 'porcini mushroom']::text[]),
    ('Morel', 'Morchella esculenta', 'fungus', ARRAY['morels', 'morel mushroom', 'yellow morel']::text[]),
    ('Black truffle', 'Tuber melanosporum', 'fungus', ARRAY['truffle', 'Périgord truffle', 'black truffles']::text[]),
    ('Enoki', 'Flammulina velutipes', 'fungus', ARRAY['enoki mushroom', 'enokitake', 'golden needle mushroom']::text[]),
    ('Maitake', 'Grifola frondosa', 'fungus', ARRAY['hen of the woods', 'maitake mushroom', 'ram''s head mushroom']::text[]),
